/* =========================================================
   YoungStars Hope Foundation-Africa — main.min.js
   Handles: header scroll state, mobile nav close-on-click,
   scroll-reveal animations, back-to-top, donation form.
   ========================================================= */
(function () {
    "use strict";

    /* ---------- Footer year ---------- */
    var footerYear = document.getElementById("footer-year");
    if (footerYear) {
        footerYear.textContent = new Date().getFullYear();
    }

    /* ---------- Header scroll state ---------- */
    var header = document.getElementById("header");
    function updateHeaderState() {
        if (!header) return;
        if (window.scrollY > 40) {
            header.classList.add("is-scrolled");
        } else {
            header.classList.remove("is-scrolled");
        }
    }
    updateHeaderState();
    window.addEventListener("scroll", updateHeaderState, { passive: true });

    /* ---------- Close mobile nav on link click ---------- */
    var mainNav = document.getElementById("mainNav");
    if (mainNav) {
        var navLinks = mainNav.querySelectorAll(".nav-link, .btn-donate");
        navLinks.forEach(function (link) {
            link.addEventListener("click", function () {
                if (mainNav.classList.contains("show") && window.bootstrap) {
                    var collapseInstance = window.bootstrap.Collapse.getOrCreateInstance(mainNav);
                    collapseInstance.hide();
                }
            });
        });
    }

    /* ---------- Scroll-reveal (fade-up) ---------- */
    var revealEls = document.querySelectorAll(".fade-up");
    if ("IntersectionObserver" in window && revealEls.length) {
        var revealObserver = new IntersectionObserver(
            function (entries, observer) {
                entries.forEach(function (entry) {
                    if (entry.isIntersecting) {
                        entry.target.classList.add("is-visible");
                        observer.unobserve(entry.target);
                    }
                });
            },
            { threshold: 0.15, rootMargin: "0px 0px -40px 0px" }
        );
        revealEls.forEach(function (el) {
            revealObserver.observe(el);
        });
    } else {
        revealEls.forEach(function (el) {
            el.classList.add("is-visible");
        });
    }

    /* ---------- Back to top ---------- */
    var backToTop = document.getElementById("backToTop");
    if (backToTop) {
        function toggleBackToTop() {
            if (window.scrollY > 500) {
                backToTop.classList.add("is-visible");
            } else {
                backToTop.classList.remove("is-visible");
            }
        }
        toggleBackToTop();
        window.addEventListener("scroll", toggleBackToTop, { passive: true });
        backToTop.addEventListener("click", function () {
            window.scrollTo({ top: 0, behavior: "smooth" });
        });
    }

    /* ---------- Donation modal logic ---------- */
    var donationForm = document.getElementById("donationForm");
    if (donationForm) {
        var amountButtons = donationForm.querySelectorAll(".amount-btn");
        var customAmount = document.getElementById("customAmount");
        var donorPhone = document.getElementById("donorPhone");
        var donationStatus = document.getElementById("donationStatus");
        var submitBtn = document.getElementById("donateSubmitBtn");
        var selectedAmount = null;

        amountButtons.forEach(function (btn) {
            btn.addEventListener("click", function () {
                amountButtons.forEach(function (b) { b.classList.remove("is-active"); });
                btn.classList.add("is-active");
                selectedAmount = parseInt(btn.getAttribute("data-amount"), 10);
                if (customAmount) customAmount.value = "";
            });
        });

        if (customAmount) {
            customAmount.addEventListener("input", function () {
                if (customAmount.value) {
                    amountButtons.forEach(function (b) { b.classList.remove("is-active"); });
                    selectedAmount = parseInt(customAmount.value, 10);
                }
            });
        }

        function isValidKenyanPhone(value) {
            var cleaned = value.replace(/\s+/g, "");
            return /^(0(7|1)\d{8}|254(7|1)\d{8})$/.test(cleaned);
        }

        function setStatus(message, type) {
            if (!donationStatus) return;
            donationStatus.textContent = message;
            donationStatus.className = "donation-status" + (type ? " " + type : "");
        }

        donationForm.addEventListener("submit", function (e) {
            e.preventDefault();

            // Honeypot check — silently ignore likely bots.
            var honeypot = document.getElementById("honeypot");
            if (honeypot && honeypot.value) {
                return;
            }

            var amount = selectedAmount || parseInt((customAmount && customAmount.value) || "0", 10);
            var phoneValue = donorPhone ? donorPhone.value.trim() : "";

            donorPhone.classList.remove("is-invalid");

            if (!amount || amount <= 0) {
                setStatus("Please select or enter a donation amount.", "error");
                return;
            }
            if (!isValidKenyanPhone(phoneValue)) {
                donorPhone.classList.add("is-invalid");
                setStatus("Please enter a valid M-Pesa phone number.", "error");
                donorPhone.focus();
                return;
            }

            // Integration point: trigger an M-Pesa STK push (or other payment
            // provider) from your backend here, passing amount + phoneValue.
            submitBtn.disabled = true;
            submitBtn.textContent = "Sending request...";
            setStatus("Sending payment request to your phone...", "");

            setTimeout(function () {
                submitBtn.disabled = false;
                submitBtn.innerHTML = '<i class="fas fa-arrow-right" aria-hidden="true"></i> Donate Now';
                setStatus("Check your phone to complete the M-Pesa payment. Thank you!", "success");
                donationForm.reset();
                amountButtons.forEach(function (b) { b.classList.remove("is-active"); });
                selectedAmount = null;
            }, 1400);
        });
    }
})();
/* =========================================================
   ABOUT PAGE — JavaScript notes

   Good news: about.html doesn't need any NEW code appended to
   main.min.js. It reuses the exact same elements/IDs your main.min.js
   already handles:
     - #header, #mainNav          (scroll state + mobile nav)
     - .fade-up                   (scroll-reveal on the About cards/images)
     - #backToTop                 (back-to-top button)
     - #donationForm + friends     (donation modal logic)
   As long as about.html keeps those same IDs/classes, your existing
   main.min.js already makes everything on the page work. Nothing to
   append here.

   ---------------------------------------------------------
   OPTIONAL — small hardening patch (not required)
   ---------------------------------------------------------
   The only thing that changed last time was two small edits INSIDE
   your existing donation submit handler (not new additions). They're
   optional but worth having:

   1) Guard against double-submits, added right at the top of the
      submit handler:

        donationForm.addEventListener("submit", function (e) {
            e.preventDefault();

            // Prevent double submission while a request is already in flight.
            if (submitBtn && submitBtn.disabled) {
                return;
            }

            // ...your existing honeypot check stays here...

   2) Safer amount parsing, replacing your existing amount line
      (the one that does `parseInt(...)` for the donation amount):

        var rawAmount = selectedAmount || parseInt((customAmount && customAmount.value) || "0", 10);
        var amount = Number.isFinite(rawAmount) ? Math.floor(rawAmount) : 0;
        var MAX_AMOUNT = 1000000;

        // then use this in your existing validation check:
        if (!amount || amount <= 0 || amount > MAX_AMOUNT) {
            setStatus("Please enter a donation amount between KSh 1 and KSh 1,000,000.", "error");
            return;
        }

   These two edits replace lines inside your existing function — they
   are not something you can paste at the bottom of the file. If you'd
   rather skip them for now, the About page will work fine without them.
   ========================================================= */
   
   /* =========================================================
   TERMS PAGE ADDITIONS — append to the end of assets/js/main.min.js.

   Highlights the current section in the sticky table-of-contents as
   you scroll. This is progressive enhancement only — the TOC links
   are plain <a href="#section"> anchors, so the page is fully usable
   (and fast/accessible) even if this script never runs.
   ========================================================= */
(function () {
    "use strict";

    var tocLinks = document.querySelectorAll(".legal-toc-link");
    var sections = document.querySelectorAll(".legal-doc > section[id]");

    if (!tocLinks.length || !sections.length || !("IntersectionObserver" in window)) {
        return;
    }

    var linkById = {};
    tocLinks.forEach(function (link) {
        var id = link.getAttribute("href").replace("#", "");
        linkById[id] = link;
    });

    var activeObserver = new IntersectionObserver(
        function (entries) {
            entries.forEach(function (entry) {
                var link = linkById[entry.target.id];
                if (!link) return;
                if (entry.isIntersecting) {
                    tocLinks.forEach(function (l) { l.classList.remove("is-active"); });
                    link.classList.add("is-active");
                }
            });
        },
        { rootMargin: "-20% 0px -70% 0px", threshold: 0 }
    );

    sections.forEach(function (section) {
        activeObserver.observe(section);
    });
})();
/* =========================================================
   GET INVOLVED PAGE ADDITIONS — append to the end of
   assets/js/main.min.js.

   Wires up the two Web3Forms-powered forms on get-involved.html
   (#volunteerForm and #newsletterForm). Both follow the same
   honeypot + inline-status pattern as the existing donation
   form above, but actually POST to the Web3Forms API since
   there's no payment step involved.

   Remember to swap "YOUR_WEB3FORMS_ACCESS_KEY" in the HTML's
   hidden access_key fields for your real key from
   https://web3forms.com before going live.
   ========================================================= */
(function () {
    "use strict";

    var WEB3FORMS_ENDPOINT = "https://api.web3forms.com/submit";

    function isValidKenyanPhone(value) {
        var cleaned = value.replace(/\s+/g, "");
        return /^(0(7|1)\d{8}|254(7|1)\d{8})$/.test(cleaned);
    }

    function isValidEmail(value) {
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());
    }

    function setFormStatus(el, message, type, center) {
        if (!el) return;
        el.textContent = message;
        el.className = "form-status" + (center ? " form-status-center" : "") + (type ? " " + type : "");
    }

    function isHoneypotTripped(form) {
        var textTrap = form.querySelector('input[name="honeypot"]');
        var checkTrap = form.querySelector('input[name="botcheck"]');
        return (textTrap && textTrap.value) || (checkTrap && checkTrap.checked);
    }

    function submitToWeb3Forms(form) {
        var formData = new FormData(form);
        var payload = {};
        formData.forEach(function (value, key) {
            payload[key] = value;
        });
        return fetch(WEB3FORMS_ENDPOINT, {
            method: "POST",
            headers: { "Content-Type": "application/json", Accept: "application/json" },
            body: JSON.stringify(payload)
        }).then(function (res) { return res.json(); });
    }

    /* ---------- Volunteer application form ---------- */
    var volunteerForm = document.getElementById("volunteerForm");
    if (volunteerForm) {
        var volStatus = document.getElementById("volunteerStatus");
        var volSubmitBtn = document.getElementById("volunteerSubmitBtn");
        var volPhone = document.getElementById("volPhone");
        var volEmail = document.getElementById("volEmail");
        var volConsent = document.getElementById("volConsent");

        volunteerForm.addEventListener("submit", function (e) {
            e.preventDefault();

            if (volSubmitBtn && volSubmitBtn.disabled) return;
            if (isHoneypotTripped(volunteerForm)) return;

            volPhone.classList.remove("is-invalid");
            volEmail.classList.remove("is-invalid");

            if (!isValidEmail(volEmail.value)) {
                volEmail.classList.add("is-invalid");
                setFormStatus(volStatus, "Please enter a valid email address.", "error");
                volEmail.focus();
                return;
            }
            if (!isValidKenyanPhone(volPhone.value)) {
                volPhone.classList.add("is-invalid");
                setFormStatus(volStatus, "Please enter a valid phone number.", "error");
                volPhone.focus();
                return;
            }
            if (volConsent && !volConsent.checked) {
                setFormStatus(volStatus, "Please confirm you agree to be contacted.", "error");
                return;
            }

            volSubmitBtn.disabled = true;
            volSubmitBtn.innerHTML = '<i class="fas fa-spinner fa-spin" aria-hidden="true"></i> Sending...';
            setFormStatus(volStatus, "Sending your application...", "");

            submitToWeb3Forms(volunteerForm)
                .then(function (data) {
                    if (data.success) {
                        setFormStatus(volStatus, "Thank you! We've received your application and will be in touch soon.", "success");
                        volunteerForm.reset();
                    } else {
                        setFormStatus(volStatus, data.message || "Something went wrong. Please try again.", "error");
                    }
                })
                .catch(function () {
                    setFormStatus(volStatus, "Network error - please check your connection and try again.", "error");
                })
                .finally(function () {
                    volSubmitBtn.disabled = false;
                    volSubmitBtn.innerHTML = '<i class="fas fa-paper-plane" aria-hidden="true"></i> Submit Application';
                });
        });
    }

    /* ---------- Newsletter subscribe form ---------- */
    var newsletterForm = document.getElementById("newsletterForm");
    if (newsletterForm) {
        var subStatus = document.getElementById("newsletterStatus");
        var subSubmitBtn = document.getElementById("newsletterSubmitBtn");
        var subEmail = document.getElementById("subEmail");

        newsletterForm.addEventListener("submit", function (e) {
            e.preventDefault();

            if (subSubmitBtn && subSubmitBtn.disabled) return;
            if (isHoneypotTripped(newsletterForm)) return;

            subEmail.classList.remove("is-invalid");

            if (!isValidEmail(subEmail.value)) {
                subEmail.classList.add("is-invalid");
                setFormStatus(subStatus, "Please enter a valid email address.", "error", true);
                subEmail.focus();
                return;
            }

            subSubmitBtn.disabled = true;
            subSubmitBtn.innerHTML = '<i class="fas fa-spinner fa-spin" aria-hidden="true"></i> Subscribing...';
            setFormStatus(subStatus, "Subscribing...", "", true);

            submitToWeb3Forms(newsletterForm)
                .then(function (data) {
                    if (data.success) {
                        setFormStatus(subStatus, "You're subscribed! Watch your inbox for updates.", "success", true);
                        newsletterForm.reset();
                    } else {
                        setFormStatus(subStatus, data.message || "Something went wrong. Please try again.", "error", true);
                    }
                })
                .catch(function () {
                    setFormStatus(subStatus, "Network error - please check your connection and try again.", "error", true);
                })
                .finally(function () {
                    subSubmitBtn.disabled = false;
                    subSubmitBtn.innerHTML = '<i class="fas fa-paper-plane" aria-hidden="true"></i> Subscribe';
                });
        });
    }
})();

/* =========================================================
   CONTACT PAGE ADDITIONS — append to the end of
   assets/js/main.min.js.

   Wires up #contactForm on contact.html. Same honeypot +
   Web3Forms fetch pattern as the GET INVOLVED PAGE ADDITIONS
   block above — reuses that block's isValidEmail, setFormStatus,
   isHoneypotTripped and submitToWeb3Forms helpers, so this must
   be appended AFTER that block (not before).
   ========================================================= */
(function () {
    "use strict";

    var contactForm = document.getElementById("contactForm");
    if (!contactForm) return;

    var status = document.getElementById("contactStatus");
    var submitBtn = document.getElementById("contactSubmitBtn");
    var email = document.getElementById("contactEmail");
    var phone = document.getElementById("contactPhone");
    var reason = document.getElementById("contactReason");
    var consent = document.getElementById("contactConsent");

    function isValidKenyanPhone(value) {
        var cleaned = value.replace(/\s+/g, "");
        return /^(0(7|1)\d{8}|254(7|1)\d{8})$/.test(cleaned);
    }

    contactForm.addEventListener("submit", function (e) {
        e.preventDefault();

        if (submitBtn && submitBtn.disabled) return;

        var textTrap = contactForm.querySelector('input[name="honeypot"]');
        if (textTrap && textTrap.value) return;

        email.classList.remove("is-invalid");
        phone.classList.remove("is-invalid");

        if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.value.trim())) {
            email.classList.add("is-invalid");
            status.textContent = "Please enter a valid email address.";
            status.className = "form-status error";
            email.focus();
            return;
        }
        if (!isValidKenyanPhone(phone.value)) {
            phone.classList.add("is-invalid");
            status.textContent = "Please enter a valid phone number.";
            status.className = "form-status error";
            phone.focus();
            return;
        }
        if (reason && !reason.value) {
            status.textContent = "Please choose a reason for contacting us.";
            status.className = "form-status error";
            reason.focus();
            return;
        }
        if (consent && !consent.checked) {
            status.textContent = "Please confirm you agree to be contacted.";
            status.className = "form-status error";
            return;
        }

        submitBtn.disabled = true;
        submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin" aria-hidden="true"></i> Sending...';
        status.textContent = "Sending your message...";
        status.className = "form-status";

        var formData = new FormData(contactForm);
        var payload = {};
        formData.forEach(function (value, key) { payload[key] = value; });

        fetch("https://api.web3forms.com/submit", {
            method: "POST",
            headers: { "Content-Type": "application/json", Accept: "application/json" },
            body: JSON.stringify(payload)
        })
            .then(function (res) { return res.json(); })
            .then(function (data) {
                if (data.success) {
                    status.textContent = "Thanks for reaching out! We'll get back to you soon.";
                    status.className = "form-status success";
                    contactForm.reset();
                } else {
                    status.textContent = data.message || "Something went wrong. Please try again.";
                    status.className = "form-status error";
                }
            })
            .catch(function () {
                status.textContent = "Network error - please check your connection and try again.";
                status.className = "form-status error";
            })
            .finally(function () {
                submitBtn.disabled = false;
                submitBtn.innerHTML = '<i class="fas fa-paper-plane" aria-hidden="true"></i> Send Message';
            });
    });
})();
/* =========================================================
   FAQ PAGE ADDITIONS — append to the end of assets/js/main.min.js.

   Wires up the search box + category filter pills on faq.html
   (#faqSearchInput, .faq-filter-btn, .faq-item). Purely a display
   filter — no network calls, no dependency on any other block in
   this file, safe to append anywhere.
   ========================================================= */
(function () {
    "use strict";

    var searchInput = document.getElementById("faqSearchInput");
    var filterBtns = document.querySelectorAll(".faq-filter-btn");
    var faqItems = document.querySelectorAll(".faq-item");
    var emptyState = document.getElementById("faqEmptyState");

    if (!faqItems.length) return;

    var activeCategory = "all";

    function applyFilters() {
        var query = (searchInput ? searchInput.value : "").trim().toLowerCase();
        var visibleCount = 0;

        faqItems.forEach(function (item) {
            var matchesCategory = activeCategory === "all" || item.getAttribute("data-category") === activeCategory;
            var haystack = item.getAttribute("data-question") || "";
            var matchesQuery = !query || haystack.indexOf(query) !== -1;

            if (matchesCategory && matchesQuery) {
                item.classList.remove("d-none");
                visibleCount++;
            } else {
                item.classList.add("d-none");
            }
        });

        if (emptyState) {
            emptyState.classList.toggle("d-none", visibleCount > 0);
        }
    }

    if (searchInput) {
        searchInput.addEventListener("input", applyFilters);
    }

    filterBtns.forEach(function (btn) {
        btn.addEventListener("click", function () {
            filterBtns.forEach(function (b) {
                b.classList.remove("is-active");
                b.setAttribute("aria-selected", "false");
            });
            btn.classList.add("is-active");
            btn.setAttribute("aria-selected", "true");
            activeCategory = btn.getAttribute("data-filter");
            applyFilters();
        });
    });
})();
/* =========================================================
   YoungStars Hope Foundation-Africa — donate.js
   Dedicated script for donate.html ONLY.

   Assumes assets/js/main.min.js has already run on this page
   (header scroll state, mobile nav, back-to-top, fade-up reveal,
   footer year) — this file only handles what's specific to the
   donate page:
     1. Story card read-more expand/collapse
     2. Animated impact stat counters (on scroll into view)
     3. Animated "where your donation goes" bar fills (on scroll)
     4. M-Pesa amount selector + STK push form (simulated)
     5. Paybill / Account number copy-to-clipboard buttons
     6. Testimonial slider (prev/next/dots, no auto-rotate)
   ========================================================= */
(function () {
    "use strict";

    /* =====================================================
       1. STORY CARD READ-MORE
       ===================================================== */
    var storyToggles = document.querySelectorAll(".donate-story-toggle");

    storyToggles.forEach(function (btn) {
        btn.addEventListener("click", function () {
            var card = btn.closest(".donate-story-card");
            if (!card) return;

            var isOpen = card.classList.toggle("is-open");
            btn.setAttribute("aria-expanded", isOpen ? "true" : "false");

            var label = btn.textContent.replace(/Read|Show less.*$/i, "").trim();
            var name = card.getAttribute("data-story") || "their";

            if (isOpen) {
                btn.innerHTML = "Show less <i class=\"fas fa-chevron-down\" aria-hidden=\"true\"></i>";
            } else {
                btn.innerHTML = defaultToggleLabel(name) + " <i class=\"fas fa-chevron-down\" aria-hidden=\"true\"></i>";
                // Scroll the card back into a comfortable view when collapsing
                // a long story, so the person isn't left staring at empty space.
                var rect = card.getBoundingClientRect();
                if (rect.top < 0) {
                    card.scrollIntoView({ behavior: "smooth", block: "start" });
                }
            }
        });
    });

    function defaultToggleLabel(storyKey) {
        var labels = {
            faith: "Read Faith's full story",
            david: "Read David's full story",
            twins: "Read their full story",
            brian: "Read Brian's full story"
        };
        return labels[storyKey] || "Read the full story";
    }

    /* =====================================================
       2. ANIMATED IMPACT STAT COUNTERS
       ===================================================== */
    var statEls = document.querySelectorAll(".donate-stat-num[data-count-to]");

    function animateCount(el) {
        var target = parseInt(el.getAttribute("data-count-to"), 10) || 0;
        var suffix = el.getAttribute("data-suffix") || "";
        var duration = 1400;
        var startTime = null;

        function easeOutQuad(t) { return t * (2 - t); }

        function step(timestamp) {
            if (startTime === null) startTime = timestamp;
            var elapsed = timestamp - startTime;
            var progress = Math.min(elapsed / duration, 1);
            var eased = easeOutQuad(progress);
            var current = Math.floor(eased * target);
            el.textContent = current.toLocaleString() + suffix;

            if (progress < 1) {
                window.requestAnimationFrame(step);
            } else {
                el.textContent = target.toLocaleString() + suffix;
            }
        }

        window.requestAnimationFrame(step);
    }

    if (statEls.length && "IntersectionObserver" in window) {
        var statObserver = new IntersectionObserver(
            function (entries, observer) {
                entries.forEach(function (entry) {
                    if (entry.isIntersecting) {
                        animateCount(entry.target);
                        observer.unobserve(entry.target);
                    }
                });
            },
            { threshold: 0.6 }
        );
        statEls.forEach(function (el) { statObserver.observe(el); });
    } else {
        // No IntersectionObserver support — just show the final numbers.
        statEls.forEach(function (el) {
            var target = parseInt(el.getAttribute("data-count-to"), 10) || 0;
            var suffix = el.getAttribute("data-suffix") || "";
            el.textContent = target.toLocaleString() + suffix;
        });
    }

    /* =====================================================
       3. IMPACT BREAKDOWN BAR FILLS
       ===================================================== */
    var barRows = document.querySelectorAll(".donate-bar-row[data-percent]");

    if (barRows.length && "IntersectionObserver" in window) {
        var barObserver = new IntersectionObserver(
            function (entries, observer) {
                entries.forEach(function (entry) {
                    if (!entry.isIntersecting) return;
                    var row = entry.target;
                    var percent = row.getAttribute("data-percent") || "0";
                    var fill = row.querySelector(".donate-bar-fill");
                    if (fill) {
                        // Defer one frame so the transition actually animates
                        // from 0 instead of jumping straight to the target.
                        window.requestAnimationFrame(function () {
                            fill.style.width = percent + "%";
                        });
                    }
                    observer.unobserve(row);
                });
            },
            { threshold: 0.4 }
        );
        barRows.forEach(function (row) { barObserver.observe(row); });
    } else {
        barRows.forEach(function (row) {
            var percent = row.getAttribute("data-percent") || "0";
            var fill = row.querySelector(".donate-bar-fill");
            if (fill) fill.style.width = percent + "%";
        });
    }

    /* =====================================================
       4. M-PESA AMOUNT SELECTOR + STK PUSH FORM
       ===================================================== */
    var donateForm = document.getElementById("donateForm");
    if (donateForm) {
        var amountBtns = donateForm.querySelectorAll(".donate-amount-btn");
        var customAmountInput = document.getElementById("donateCustomAmount");
        var phoneInput = document.getElementById("donatePhone");
        var consentInput = document.getElementById("donateConsent");
        var honeypotInput = document.getElementById("donateHoneypot");
        var statusEl = document.getElementById("donateStatus2");
        var submitBtn = document.getElementById("donateSubmitBtn2");
        var selectedAmount = null;

        amountBtns.forEach(function (btn) {
            btn.addEventListener("click", function () {
                amountBtns.forEach(function (b) { b.classList.remove("is-active"); });
                btn.classList.add("is-active");
                selectedAmount = parseInt(btn.getAttribute("data-amount"), 10);
                if (customAmountInput) customAmountInput.value = "";
            });
        });

        if (customAmountInput) {
            customAmountInput.addEventListener("input", function () {
                if (customAmountInput.value) {
                    amountBtns.forEach(function (b) { b.classList.remove("is-active"); });
                    selectedAmount = parseInt(customAmountInput.value, 10);
                }
            });
        }

        function isValidKenyanPhone(value) {
            var cleaned = value.replace(/\s+/g, "");
            return /^(0(7|1)\d{8}|254(7|1)\d{8})$/.test(cleaned);
        }

        function setDonateStatus(message, type) {
            if (!statusEl) return;
            statusEl.textContent = message;
            statusEl.className = "form-status" + (type ? " " + type : "");
        }

        donateForm.addEventListener("submit", function (e) {
            e.preventDefault();

            if (submitBtn && submitBtn.disabled) return;
            if (honeypotInput && honeypotInput.value) return; // silently ignore likely bots

            var amount = selectedAmount || parseInt((customAmountInput && customAmountInput.value) || "0", 10);
            var phoneValue = phoneInput ? phoneInput.value.trim() : "";

            phoneInput.classList.remove("is-invalid");

            if (!amount || amount <= 0) {
                setDonateStatus("Please select or enter a donation amount.", "error");
                return;
            }
            if (!isValidKenyanPhone(phoneValue)) {
                phoneInput.classList.add("is-invalid");
                setDonateStatus("Please enter a valid M-Pesa phone number.", "error");
                phoneInput.focus();
                return;
            }
            if (consentInput && !consentInput.checked) {
                setDonateStatus("Please agree to the Terms and Privacy Policy to continue.", "error");
                return;
            }

            // Integration point: trigger a real M-Pesa STK push from your
            // backend here, passing `amount` and `phoneValue`. This is a
            // simulated response so the page works standalone until that
            // backend integration is wired up.
            submitBtn.disabled = true;
            submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin" aria-hidden="true"></i> Sending request...';
            setDonateStatus("Sending payment request to your phone...", "");

            window.setTimeout(function () {
                submitBtn.disabled = false;
                submitBtn.innerHTML = '<i class="fas fa-arrow-right" aria-hidden="true"></i> Send STK Push';
                setDonateStatus("Check your phone to complete the M-Pesa payment. Thank you for giving!", "success");
                donateForm.reset();
                amountBtns.forEach(function (b) { b.classList.remove("is-active"); });
                selectedAmount = null;
            }, 1400);
        });
    }

    /* =====================================================
       5. PAYBILL / ACCOUNT NUMBER COPY BUTTONS
       ===================================================== */
    var copyBtns = document.querySelectorAll(".donate-copy-btn[data-copy-target]");

    copyBtns.forEach(function (btn) {
        var originalLabel = btn.innerHTML;

        btn.addEventListener("click", function () {
            var targetId = btn.getAttribute("data-copy-target");
            var targetEl = document.getElementById(targetId);
            if (!targetEl) return;

            var text = targetEl.textContent.trim();

            copyTextToClipboard(text).then(function (ok) {
                if (!ok) return;
                btn.classList.add("is-copied");
                btn.innerHTML = '<i class="fas fa-check" aria-hidden="true"></i> Copied';
                window.setTimeout(function () {
                    btn.classList.remove("is-copied");
                    btn.innerHTML = originalLabel;
                }, 1800);
            });
        });
    });

    function copyTextToClipboard(text) {
        if (navigator.clipboard && window.isSecureContext) {
            return navigator.clipboard.writeText(text).then(
                function () { return true; },
                function () { return false; }
            );
        }

        // Fallback for browsers/contexts without the async Clipboard API.
        return new Promise(function (resolve) {
            var textarea = document.createElement("textarea");
            textarea.value = text;
            textarea.style.position = "fixed";
            textarea.style.left = "-9999px";
            document.body.appendChild(textarea);
            textarea.focus();
            textarea.select();
            var success = false;
            try {
                success = document.execCommand("copy");
            } catch (err) {
                success = false;
            }
            document.body.removeChild(textarea);
            resolve(success);
        });
    }

    /* =====================================================
       6. TESTIMONIAL SLIDER
       ===================================================== */
    var slider = document.getElementById("testimonialSlider");
    if (slider) {
        var track = slider.querySelector(".donate-testimonial-track");
        var slides = slider.querySelectorAll(".donate-testimonial-slide");
        var prevBtn = document.getElementById("testimonialPrev");
        var nextBtn = document.getElementById("testimonialNext");
        var dotsContainer = document.getElementById("testimonialDots");
        var currentIndex = 0;

        slides.forEach(function (slide, i) {
            var dot = document.createElement("button");
            dot.type = "button";
            dot.className = "donate-testimonial-dot" + (i === 0 ? " is-active" : "");
            dot.setAttribute("aria-label", "Show testimonial " + (i + 1));
            dot.setAttribute("role", "tab");
            dot.addEventListener("click", function () { goToSlide(i); });
            dotsContainer.appendChild(dot);
        });

        var dots = dotsContainer.querySelectorAll(".donate-testimonial-dot");

        function goToSlide(index) {
            var total = slides.length;
            currentIndex = (index + total) % total;
            track.style.transform = "translateX(-" + (currentIndex * 100) + "%)";
            dots.forEach(function (dot, i) {
                dot.classList.toggle("is-active", i === currentIndex);
            });
        }

        if (prevBtn) prevBtn.addEventListener("click", function () { goToSlide(currentIndex - 1); });
        if (nextBtn) nextBtn.addEventListener("click", function () { goToSlide(currentIndex + 1); });

        // Basic swipe support on touch devices.
        var touchStartX = null;
        track.addEventListener("touchstart", function (e) {
            touchStartX = e.changedTouches[0].clientX;
        }, { passive: true });
        track.addEventListener("touchend", function (e) {
            if (touchStartX === null) return;
            var deltaX = e.changedTouches[0].clientX - touchStartX;
            if (Math.abs(deltaX) > 40) {
                goToSlide(deltaX < 0 ? currentIndex + 1 : currentIndex - 1);
            }
            touchStartX = null;
        }, { passive: true });
    }
})();
/* =========================================================
   YoungStars Hope Foundation-Africa — team.js
   Dedicated script for team.html ONLY.

   The flip itself is pure CSS (:hover / :focus-within on
   .team-flip-card, see team.css) — this file only adds what CSS
   can't do on its own:
     1. Tap-to-flip on touch devices, which have no :hover state
     2. Keeping a click on "Read More" from being swallowed by
        the card's own tap-to-flip handler
     3. Closing a flipped card when the person taps elsewhere

   Works for any number of .team-flip-card elements added later —
   nothing here is hard-coded to James's card specifically.
   ========================================================= */
(function () {
    "use strict";

    var flipCards = document.querySelectorAll(".team-flip-card");
    if (!flipCards.length) return;

    // Touch devices don't have a reliable :hover, so give them an
    // explicit tap-to-flip instead. Detected once, not per-tap.
    var isTouchDevice = window.matchMedia("(hover: none)").matches;

    flipCards.forEach(function (card) {
        var readMoreLink = card.querySelector(".team-flip-readmore");

        // Let the "Read More" link behave like a normal link — don't
        // let the card's own click handler intercept or re-flip it.
        if (readMoreLink) {
            readMoreLink.addEventListener("click", function (e) {
                e.stopPropagation();
            });
        }

        if (!isTouchDevice) return;

        card.addEventListener("click", function (e) {
            // A click that landed on the Read More link should navigate,
            // not toggle the flip state back.
            if (e.target.closest(".team-flip-readmore")) return;

            var alreadyOpen = card.classList.contains("is-flipped");

            // Close any other flipped card first, so only one card is
            // showing its back at a time on small screens.
            flipCards.forEach(function (other) {
                if (other !== card) other.classList.remove("is-flipped");
            });

            card.classList.toggle("is-flipped", !alreadyOpen);
        });
    });

    // Tapping anywhere outside all flip cards closes whichever one
    // is currently open, so the person isn't stuck on the back face.
    if (isTouchDevice) {
        document.addEventListener("click", function (e) {
            var tappedInsideCard = e.target.closest(".team-flip-card");
            if (tappedInsideCard) return;

            flipCards.forEach(function (card) {
                card.classList.remove("is-flipped");
            });
        });
    }
})();